#!/usr/bin/env node

const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const TARGET_MS = 60_000;

function usage() {
  console.error([
    "Usage:",
    "  node bin/validate-timed-payout-proof.js <proof-summary.json>",
    "",
    "Validates a live devnet timed_payout proof generated by npm run earn:devnet.",
  ].join("\n"));
  process.exit(1);
}

function assert(condition, message) {
  if (!condition) throw new Error(message);
}

function loadJson(file) {
  return JSON.parse(fs.readFileSync(file, "utf8"));
}

function resolveEvidence(file) {
  const resolved = path.isAbsolute(file) ? path.resolve(file) : path.resolve(ROOT, file);
  assert(resolved === ROOT || resolved.startsWith(`${ROOT}${path.sep}`), `${file} must stay inside repo root`);
  return resolved;
}

function assertSignature(value, label) {
  assert(typeof value === "string" && /^[1-9A-HJ-NP-Za-km-z]{40,100}$/.test(value), `${label} must look like a Solana signature`);
}

function validate(file) {
  const summary = loadJson(file);
  const timed = summary.timed_payout;
  assert(summary.ok === true, "proof summary must be ok");
  assert(summary.kind === "tasc.solana-devnet.proof", "proof summary kind mismatch");
  assert(summary.no_new_dependencies === true, "proof summary must declare no new dependencies");
  assert(summary.key_material_printed === false, "proof summary must not print key material");
  assert(summary.rpc_url_printed === false, "proof summary must not print full RPC URL");
  assert(timed && timed.ok === true, "timed_payout must be ok");
  assert(timed.branch === "release", "timed_payout branch must be release");
  assertSignature(timed.claim_signature, "claim_signature");
  assertSignature(timed.attest_signature, "attest_signature");
  assertSignature(timed.release_signature, "release_signature");

  const payout = timed.payout || {};
  assert(payout.display_reward === "10 USDC", "payout display reward mismatch");
  assert(payout.amount === "10000000", "payout amount must be 10000000 base units");
  assert(payout.destination_role === "worker", "payout destination must be worker");
  assert(payout.completed_status === "Released", "payout must complete as Released");
  assert(payout.settlement_action === "release", "settlement action must be release");
  assert(payout.vault_balance_after === "0", "vault must be empty after release");
  assert(BigInt(payout.destination_balance_after || "0") >= BigInt(payout.amount), "worker destination must hold the released amount");

  const timing = timed.timing || {};
  assert(timing.target_ms === TARGET_MS, "timing target must be 60000ms");
  assert(timing.live_deadline === "60s", "timed proof should use a 60s live deadline");
  assert(Number.isInteger(timing.claim_to_release_ms), "claim_to_release_ms must be integer");
  assert(Number.isInteger(timing.claim_to_completed_index_ms), "claim_to_completed_index_ms must be integer");
  assert(timing.claim_to_release_ms >= 0, "claim_to_release_ms must be nonnegative");
  assert(timing.claim_to_completed_index_ms >= timing.claim_to_release_ms, "completed-index timing should be >= release timing");
  assert(timing.claim_to_release_ms <= TARGET_MS, "claim-to-release exceeded 60 seconds");
  assert(timing.claim_to_completed_index_ms <= TARGET_MS, "claim-to-completed-index exceeded 60 seconds");
  assert(timing.under_60s_to_release_confirmation === true, "release under_60s flag must be true");
  assert(timing.under_60s_to_completed_index === true, "completed-index under_60s flag must be true");

  for (const [label, evidenceFile] of Object.entries(timed.evidence || {})) {
    assert(typeof evidenceFile === "string" && evidenceFile.length > 0, `${label} evidence path missing`);
    assert(fs.existsSync(resolveEvidence(evidenceFile)), `${label} evidence file does not exist`);
  }

  return {
    ok: true,
    proof_summary: path.relative(ROOT, path.resolve(file)),
    run_id: summary.run_id,
    task_hash: timed.task_hash,
    task_account: timed.task_account,
    payout: {
      display_reward: payout.display_reward,
      amount: payout.amount,
      token_mint: payout.token_mint,
      destination_token_account: payout.destination_token_account,
      completed_status: payout.completed_status,
      vault_balance_after: payout.vault_balance_after,
      destination_balance_after: payout.destination_balance_after,
    },
    timing: {
      claim_to_release_ms: timing.claim_to_release_ms,
      claim_to_completed_index_ms: timing.claim_to_completed_index_ms,
      target_ms: timing.target_ms,
      under_60s_to_release_confirmation: timing.under_60s_to_release_confirmation,
      under_60s_to_completed_index: timing.under_60s_to_completed_index,
    },
    signatures: {
      claim: timed.claim_signature,
      attest: timed.attest_signature,
      release: timed.release_signature,
    },
    no_new_dependencies: true,
  };
}

function main() {
  const [file, ...rest] = process.argv.slice(2);
  if (!file || rest.length > 0) usage();
  process.stdout.write(`${JSON.stringify(validate(file), null, 2)}\n`);
}

if (require.main === module) {
  try {
    main();
  } catch (error) {
    console.error(`validate-timed-payout-proof: ${error.message}`);
    process.exit(1);
  }
}

module.exports = {
  validate,
};
